from itertools import combinations

class Solution:
    def maximumScore(self, nums, k):
        n = len(nums)
        best = float('-inf')
        max_m = min(k, n)
        for m in range(0, max_m + 1):
            parts_count = m if m > 0 else 1
            if parts_count > k:
                continue
            gap_combos = [()] if m == 0 else combinations(range(n), m)
            for cuts in gap_combos:
                if cuts:
                    cs = sorted(cuts)
                    parts = []
                    mm = len(cs)
                    for t in range(mm):
                        start = (cs[t] + 1) % n
                        nxt = cs[(t + 1) % mm]
                        length = (nxt - cs[t]) % n
                        if length == 0:
                            length = n
                        parts.append([(start + o) % n for o in range(length)])
                else:
                    parts = [list(range(n))]
                score = 0
                for idxs in parts:
                    vals = [nums[i] for i in idxs]
                    score += max(vals) - min(vals)
                if score > best:
                    best = score
        return best

