class Solution:
    def maximumScore(self, nums, k):
        def best_linear(arr, kk):
            n = len(arr)
            NEG = float('-inf')
            dp = [[NEG] * (kk + 1) for _ in range(n + 1)]
            dp[0][0] = 0
            for i in range(1, n + 1):
                mx = arr[i - 1]
                mn = arr[i - 1]
                for p in range(i - 1, -1, -1):
                    if p < i - 1:
                        if arr[p] > mx:
                            mx = arr[p]
                        if arr[p] < mn:
                            mn = arr[p]
                    rng = mx - mn
                    for j in range(1, kk + 1):
                        if dp[p][j - 1] != NEG:
                            val = dp[p][j - 1] + rng
                            if val > dp[i][j]:
                                dp[i][j] = val
            return max(dp[n][1:kk + 1])

        n = len(nums)
        kk = min(k, n)
        best = float('-inf')
        for r in range(n):
            rotated = nums[r:] + nums[:r]
            val = best_linear(rotated, kk)
            if val > best:
                best = val
        return best

