var maximumScore = function(nums, k) {
    function bestLinear(arr, kk) {
        const n = arr.length;
        const NEG = -Infinity;
        const dp = [];
        for (let i = 0; i <= n; i++) dp.push(new Array(kk + 1).fill(NEG));
        dp[0][0] = 0;
        for (let i = 1; i <= n; i++) {
            let mx = arr[i - 1], mn = arr[i - 1];
            for (let p = i - 1; p >= 0; p--) {
                if (p < i - 1) {
                    if (arr[p] > mx) mx = arr[p];
                    if (arr[p] < mn) mn = arr[p];
                }
                const rng = mx - mn;
                for (let j = 1; j <= kk; j++) {
                    if (dp[p][j - 1] !== NEG) {
                        const val = dp[p][j - 1] + rng;
                        if (val > dp[i][j]) dp[i][j] = val;
                    }
                }
            }
        }
        return Math.max(...dp[n].slice(1, kk + 1));
    }

    const n = nums.length;
    const kk = Math.min(k, n);
    let best = -Infinity;
    for (let r = 0; r < n; r++) {
        const rotated = nums.slice(r).concat(nums.slice(0, r));
        const val = bestLinear(rotated, kk);
        if (val > best) best = val;
    }
    return best;
};
